m_uuid(),\n  parcel_id TEXT NOT NULL REFERENCES public.parcels(parcel_id),\n  date DATE NOT NULL,\n  crop TEXT NOT NULL,\n  production_kg NUMERIC,\n  notes TEXT,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.harvests ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read harvests\\" ON public.harvests FOR SELECT USING (true)","CREATE POLICY \\"Public insert harvests\\" ON public.harvests FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public delete harvests\\" ON public.harvests FOR DELETE USING (true)"}	da4cca3b-dfd6-4ad7-be5f-62d9c0c902de
20260310000001	{"-- ============================================================\n-- AGRÍCOLA MARVIC 360 — Migración v2\n-- Esquema extendido completo\n-- ============================================================\n\n-- ── ENUMS ────────────────────────────────────────────────────\nCREATE TYPE tipo_riego AS ENUM (\n  'goteo', 'tradicional', 'aspersion', 'ninguno'\n)","CREATE TYPE estado_parcela AS ENUM (\n  'activa', 'plantada', 'preparacion', 'cosechada', 'vacia', 'baja'\n)","CREATE TYPE tipo_suelo AS ENUM (\n  'arcilloso', 'franco', 'arenoso', 'limoso', 'franco_arcilloso'\n)","CREATE TYPE tipo_residuo AS ENUM (\n  'plastico_acolchado', 'cinta_riego', 'rafia', 'envase_fitosanitario', 'otro'\n)","CREATE TYPE estado_certificacion AS ENUM (\n  'vigente', 'suspendida', 'en_tramite', 'caducada'\n)","-- ── CATÁLOGO DE CULTIVOS ──────────────────────────────────────\nCREATE TABLE public.cultivos_catalogo (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  nombre_interno TEXT UNIQUE NOT NULL,\n  nombre_display TEXT NOT NULL,\n  ciclo_dias INTEGER NOT NULL,\n  rendimiento_kg_ha NUMERIC(10,2),\n  marco_std_entre_lineas_cm NUMERIC(6,2),\n  marco_std_entre_plantas_cm NUMERIC(6,2),\n  kg_plastico_por_ha NUMERIC(10,2),\n  m_cinta_riego_por_ha NUMERIC(10,2),\n  es_ecologico BOOLEAN DEFAULT true,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.cultivos_catalogo ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read cultivos_catalogo\\"\n  ON public.cultivos_catalogo FOR SELECT USING (true)","-- ── CUADRILLAS ───────────────────────────────────────────────\nCREATE TABLE public.cuadrillas (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  nombre TEXT NOT NULL,\n  empresa TEXT,\n  nif TEXT,\n  responsable TEXT,\n  telefono TEXT,\n  activa BOOLEAN DEFAULT true,\n  qr_code TEXT UNIQUE,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.cuadrillas ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read cuadrillas\\"\n  ON public.cuadrillas FOR SELECT USING (true)","CREATE POLICY \\"Public insert cuadrillas\\"\n  ON public.cuadrillas FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update cuadrillas\\"\n  ON public.cuadrillas FOR UPDATE USING (true)","-- ── CAMIONES ─────────────────────────────────────────────────\nCREATE TABLE public.camiones (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  matricula TEXT NOT NULL UNIQUE,\n  empresa_transporte TEXT,\n  tipo TEXT CHECK (tipo IN ('propio', 'contratado')),\n  capacidad_kg NUMERIC(10,2),\n  activo BOOLEAN DEFAULT true,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.camiones ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read camiones\\"\n  ON public.camiones FOR SELECT USING (true)","CREATE POLICY \\"Public insert camiones\\"\n  ON public.camiones FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update camiones\\"\n  ON public.camiones FOR UPDATE USING (true)","-- ── AMPLIAR PARCELAS ─────────────────────────────────────────\nALTER TABLE public.parcels\n  ADD COLUMN IF NOT EXISTS tipo_suelo tipo_suelo,\n  ADD COLUMN IF NOT EXISTS ph_suelo NUMERIC(4,2),\n  ADD COLUMN IF NOT EXISTS materia_organica_pct NUMERIC(5,2),\n  ADD COLUMN IF NOT EXISTS ultima_analisis_suelo DATE,\n  ADD COLUMN IF NOT EXISTS irrigation_type_v2 tipo_riego","-- ── AMPLIAR PLANTACIONES ─────────────────────────────────────\nALTER TABLE public.plantings\n  ADD COLUMN IF NOT EXISTS variedad TEXT,\n  ADD COLUMN IF NOT EXISTS marco_cm_entre_lineas NUMERIC(6,2),\n  ADD COLUMN IF NOT EXISTS marco_cm_entre_plantas NUMERIC(6,2),\n  ADD COLUMN IF NOT EXISTS num_plantas_real INTEGER,\n  ADD COLUMN IF NOT EXISTS lote_semilla TEXT,\n  ADD COLUMN IF NOT EXISTS proveedor_semilla TEXT,\n  ADD COLUMN IF NOT EXISTS fecha_cosecha_estimada DATE,\n  ADD COLUMN IF NOT EXISTS sistema_riego tipo_riego","-- ── AMPLIAR REGISTROS DE TRABAJO ─────────────────────────────\nALTER TABLE public.work_records\n  ADD COLUMN IF NOT EXISTS cuadrilla_id UUID REFERENCES public.cuadrillas(id),\n  ADD COLUMN IF NOT EXISTS hora_entrada TIMESTAMPTZ,\n  ADD COLUMN IF NOT EXISTS hora_salida TIMESTAMPTZ,\n  ADD COLUMN IF NOT EXISTS qr_scan_timestamp TIMESTAMPTZ","-- ── CUADRILLAS POR OPERACIÓN (N:M) ───────────────────────────\nCREATE TABLE public.work_records_cuadrillas (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  work_record_id UUID NOT NULL REFERENCES public.work_records(id) ON DELETE CASCADE,\n  cuadrilla_id UUID NOT NULL REFERENCES public.cuadrillas(id),\n  num_trabajadores INTEGER NOT NULL DEFAULT 1,\n  hora_entrada TIMESTAMPTZ,\n  hora_salida TIMESTAMPTZ,\n  created_at TIMESTAMPTZ DEFAULT now(),\n  UNIQUE(work_record_id, cuadrilla_id)\n)","ALTER TABLE public.work_records_cuadrillas ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read work_records_cuadrillas\\"\n  ON public.work_records_cuadrillas FOR SELECT USING (true)","CREATE POLICY \\"Public insert work_records_cuadrillas\\"\n  ON public.work_records_cuadrillas FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update work_records_cuadrillas\\"\n  ON public.work_records_cuadrillas FOR UPDATE USING (true)","-- ── RESIDUOS ─────────────────────────────────────────────────\nCREATE TABLE public.residuos_operacion (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  parcel_id TEXT NOT NULL REFERENCES public.parcels(parcel_id),\n  operacion_id UUID REFERENCES public.work_records(id),\n  tipo_residuo tipo_residuo NOT NULL,\n  kg_instalados NUMERIC(10,2),\n  kg_retirados NUMERIC(10,2),\n  proveedor TEXT,\n  lote_material TEXT,\n  gestor_residuos TEXT,\n  fecha_instalacion DATE,\n  fecha_retirada DATE,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.residuos_operacion ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read residuos_operacion\\"\n  ON public.residuos_operacion FOR SELECT USING (true)","CREATE POLICY \\"Public insert residuos_operacion\\"\n  ON public.residuos_operacion FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update residuos_operacion\\"\n  ON public.residuos_operacion FOR UPDATE USING (true)","-- ── TICKETS DE PESAJE ────────────────────────────────────────\nCREATE TABLE public.tickets_pesaje (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  harvest_id UUID NOT NULL REFERENCES public.harvests(id),\n  camion_id UUID REFERENCES public.camiones(id),\n  matricula_manual TEXT,\n  destino TEXT NOT NULL,\n  peso_bruto_kg NUMERIC(10,2) NOT NULL,\n  peso_tara_kg NUMERIC(10,2) NOT NULL DEFAULT 0,\n  peso_neto_kg NUMERIC(10,2) GENERATED ALWAYS AS (peso_bruto_kg - peso_tara_kg) STORED,\n  conductor TEXT,\n  hora_salida TIMESTAMPTZ DEFAULT now(),\n  numero_albaran TEXT UNIQUE,\n  observaciones TEXT,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.tickets_pesaje ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read tickets_pesaje\\"\n  ON public.tickets_pesaje FOR SELECT USING (true)","CREATE POLICY \\"Public insert tickets_pesaje\\"\n  ON public.tickets_pesaje FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update tickets_pesaje\\"\n  ON public.tickets_pesaje FOR UPDATE USING (true)","-- ── CERTIFICACIONES ECOLÓGICAS ───────────────────────────────\nCREATE TABLE public.certificaciones_parcela (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  parcel_id TEXT NOT NULL REFERENCES public.parcels(parcel_id),\n  entidad_certificadora TEXT NOT NULL,\n  numero_expediente TEXT,\n  campana TEXT NOT NULL,\n  fecha_inicio DATE NOT NULL,\n  fecha_fin DATE,\n  estado estado_certificacion NOT NULL DEFAULT 'en_tramite',\n  observaciones TEXT,\n  created_at TIMESTAMPTZ DEFAULT now()\n)","ALTER TABLE public.certificaciones_parcela ENABLE ROW LEVEL SECURITY","CREATE POLICY \\"Public read certificaciones_parcela\\"\n  ON public.certificaciones_parcela FOR SELECT USING (true)","CREATE POLICY \\"Public insert certificaciones_parcela\\"\n  ON public.certificaciones_parcela FOR INSERT WITH CHECK (true)","CREATE POLICY \\"Public update certificaciones_parcela\\"\n  ON public.certificaciones_parcela FOR UPDATE USING (true)","-- ── ÍNDICES DE RENDIMIENTO ───────────────────────────────────\nCREATE INDEX IF NOT EXISTS idx_plantings_parcel_date\n  ON public.plantings(parcel_id, date DESC)","CREATE INDEX IF NOT EXISTS idx_harvests_parcel_date\n  ON public.harvests(parcel_id, date DESC)","CREATE INDEX IF NOT EXISTS idx_work_records_parcel_date\n  ON public.work_records(parcel_id, date DESC)","CREATE INDEX IF NOT EXISTS idx_residuos_parcel\n  ON public.residuos_operacion(parcel_id)","CREATE INDEX IF NOT EXISTS idx_tickets_harvest\n  ON public.tickets_pesaje(harvest_id)","CREATE INDEX IF NOT EXISTS idx_certificaciones_parcel\n  ON public.certificaciones_parcela(parcel_id)"}	marvic_v2_schema
